def last_non_empty_string(s: str) -> str:
    # Count frequency of each character
    freq = {}
    for ch in s:
        freq[ch] = freq.get(ch, 0) + 1

    # Find the maximum frequency
    max_freq = max(freq.values())

    # Collect characters that appear max_freq times
    result_chars = [ch for ch in freq if freq[ch] == max_freq]
    result_set = set(result_chars)

    # Build result by taking the last occurrence of each such character
    result = []
    for ch in reversed(s):
        if ch in result_set:
            result.append(ch)
            result_set.remove(ch)

    return ''.join(reversed(result))
